class Solution {
    public int findIntegers(int n) {
        int count = 0;
        for (int i = 0; i <= n; i++) {
            if (hasConsecutiveOnes(i)) continue;
            count++;
        }
        return count;
    }
    private boolean hasConsecutiveOnes(int num) {
        String binary = Integer.toBinaryString(num);
        for (int i = 1; i < binary.length(); i++) {
            if (binary.charAt(i) == '1' && binary.charAt(i - 1) == '1') {
                return true;
            }
        }
        return false;
    }
}
